-- ██████████████████████████████████████████████████████\n--           Extreme Solutions  |  ES-UI Library\n--                       v1.2\n--      Custom UI framework for all ES Hub scripts\n-- ██████████████████████████████████████████████████████\n\n-- ══════════════════════════════════════════════════════\n--  MODULE\n-- ══════════════════════════════════════════════════════\n\nlocal ESLib = {}\nESLib.__index = ESLib\n\n-- ══════════════════════════════════════════════════════\n--  SERVICES\n-- ══════════════════════════════════════════════════════\n\nlocal Players      = game:GetService("Players")\nlocal TweenService = game:GetService("TweenService")\nlocal UIS          = game:GetService("UserInputService")\nlocal HttpService  = game:GetService("HttpService")\nlocal RunService   = game:GetService("RunService")\n\nlocal LocalPlayer = Players.LocalPlayer\nlocal PlayerGui   = LocalPlayer:WaitForChild("PlayerGui")\n\n-- ══════════════════════════════════════════════════════\n--  THEME  (ES Green)\n-- ══════════════════════════════════════════════════════\n\nlocal T = {\n    -- Backgrounds\n    bg          = Color3.fromRGB( 8,  12,  8),\n    sidebar     = Color3.fromRGB(11,  16, 11),\n    panel       = Color3.fromRGB(14,  20, 14),\n    card        = Color3.fromRGB(19,  26, 19),\n    cardHov     = Color3.fromRGB(24,  32, 24),\n    input       = Color3.fromRGB(10,  15, 10),\n    overlay     = Color3.fromRGB(11,  15, 11),\n\n    -- Accent (ES lime-green)\n    accent      = Color3.fromRGB( 98, 210,  60),\n    accentDark  = Color3.fromRGB( 65, 145,  35),\n    accentLight = Color3.fromRGB(140, 235, 100),\n\n    -- Tab states\n    tabActive   = Color3.fromRGB(18,  30, 18),\n    tabHov      = Color3.fromRGB(15,  22, 15),\n\n    -- Text\n    textPri     = Color3.fromRGB(228, 242, 228),\n    textSec     = Color3.fromRGB(140, 175, 140),\n    textDim     = Color3.fromRGB( 70, 100,  70),\n\n    -- Status\n    success     = Color3.fromRGB( 70, 200, 108),\n    error       = Color3.fromRGB(210,  65,  65),\n    warning     = Color3.fromRGB(238, 175,  42),\n\n    -- Toggle\n    toggleOn    = Color3.fromRGB( 98, 210,  60),\n    toggleOff   = Color3.fromRGB( 30,  45,  30),\n\n    -- Borders\n    border      = Color3.fromRGB( 40,  70,  40),\n    borderHov   = Color3.fromRGB( 65, 110,  65),\n\n    white       = Color3.fromRGB(255, 255, 255),\n    black       = Color3.fromRGB(  0,   0,   0),\n}\n\n-- ══════════════════════════════════════════════════════\n--  LAYOUT CONSTANTS\n-- ══════════════════════════════════════════════════════\n\nlocal WIN_W     = 600\nlocal WIN_H     = 420\nlocal HEADER_H  = 42\nlocal SIDEBAR_W = 152\nlocal CONTENT_W = WIN_W - SIDEBAR_W\nlocal CONTENT_H = WIN_H - HEADER_H\n\n-- ══════════════════════════════════════════════════════\n--  HELPERS\n-- ══════════════════════════════════════════════════════\n\nlocal function tw(obj, props, t, style, dir)\n    TweenService:Create(\n        obj,\n        TweenInfo.new(t or 0.2, style or Enum.EasingStyle.Quart, dir or Enum.EasingDirection.Out),\n        props\n    ):Play()\nend\n\nlocal function corner(parent, radius)\n    local c = Instance.new("UICorner")\n    c.CornerRadius = UDim.new(0, radius or 8)\n    c.Parent = parent\n    return c\nend\n\nlocal function stroke(parent, color, thickness)\n    local s = Instance.new("UIStroke")\n    s.Color           = color or T.border\n    s.Thickness       = thickness or 1\n    s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border\n    s.Parent          = parent\n    return s\nend\n\n-- NOTE: All padding values use UDim.new (not UDim2.new) — UIPadding requires UDim\nlocal function pad(parent, top, right, bot, left)\n    local p = Instance.new("UIPadding")\n    p.PaddingTop    = UDim.new(0, top   or 0)\n    p.PaddingRight  = UDim.new(0, right or 0)\n    p.PaddingBottom = UDim.new(0, bot   or 0)\n    p.PaddingLeft   = UDim.new(0, left  or 0)\n    p.Parent        = parent\nend\n\nlocal function listLayout(parent, spacing, dir)\n    local l = Instance.new("UIListLayout")\n    l.FillDirection = dir or Enum.FillDirection.Vertical\n    l.SortOrder     = Enum.SortOrder.LayoutOrder\n    l.Padding       = UDim.new(0, spacing or 5)\n    l.Parent        = parent\n    return l\nend\n\nlocal function newFrame(props)\n    local f = Instance.new("Frame")\n    f.BorderSizePixel = 0\n    for k, v in pairs(props or {}) do f[k] = v end\n    return f\nend\n\nlocal function newLabel(props)\n    local l = Instance.new("TextLabel")\n    l.BackgroundTransparency = 1\n    l.BorderSizePixel        = 0\n    l.Font                   = Enum.Font.Gotham\n    l.TextSize               = 13\n    l.TextColor3             = T.textPri\n    l.TextXAlignment         = Enum.TextXAlignment.Left\n    for k, v in pairs(props or {}) do l[k] = v end\n    return l\nend\n\nlocal function newBtn(props)\n    local b = Instance.new("TextButton")\n    b.BorderSizePixel   = 0\n    b.AutoButtonColor   = false\n    b.Font              = Enum.Font.Gotham\n    b.TextSize          = 13\n    b.TextColor3        = T.textPri\n    b.TextXAlignment    = Enum.TextXAlignment.Left\n    for k, v in pairs(props or {}) do b[k] = v end\n    return b\nend\n\nlocal function scrollFrame(parent, zindex)\n    local s = Instance.new("ScrollingFrame")\n    s.BackgroundTransparency = 1\n    s.BorderSizePixel        = 0\n    s.ScrollBarThickness     = 3\n    s.ScrollBarImageColor3   = T.accent\n    s.CanvasSize             = UDim2.new(0, 0, 0, 0)\n    s.AutomaticCanvasSize    = Enum.AutomaticSize.Y\n    s.ZIndex                 = zindex or 2\n    s.Parent                 = parent\n    return s\nend\n\n-- ══════════════════════════════════════════════════════\n--  CONFIG PERSISTENCE\n-- ══════════════════════════════════════════════════════\n\nlocal function saveConfig(folder, file, data)\n    pcall(function()\n        if not isfolder(folder) then makefolder(folder) end\n        writefile(folder .. "/" .. file .. ".json", HttpService:JSONEncode(data))\n    end)\nend\n\nlocal function loadCfg(folder, file)\n    local ok, result = pcall(function()\n        return HttpService:JSONDecode(readfile(folder .. "/" .. file .. ".json"))\n    end)\n    return ok and type(result) == "table" and result or {}\nend\n\n-- ══════════════════════════════════════════════════════\n--  NOTIFICATION SYSTEM\n-- ══════════════════════════════════════════════════════\n\nlocal notifGui = Instance.new("ScreenGui")\nofnotifGui.Name           = "ESNotifications"\nnotifGui.ResetOnSpawn   = false\nnotifGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling\nnotifGui.IgnoreGuiInset = true\nnotifGui.DisplayOrder   = 200\nnotifGui.Parent         = PlayerGui\n\nlocal notifHolder = newFrame({\n    Size                   = UDim2.new(0, 290, 1, 0),\n    Position               = UDim2.new(1, -300, 0, 0),\n    BackgroundTransparency = 1,\n    Parent                 = notifGui,\n})\nlistLayout(notifHolder, 8)\npad(notifHolder, 14, 0, 14, 0)\n\nlocal function notify(title, content, ntype, duration)\n    ntype    = ntype    or "info"\n    duration = duration or 4\n\n    local col = ntype == "success" and T.success\n             or ntype == "error"   and T.error\n             or ntype == "warning" and T.warning\n             or T.accent\n\n    local card = newFrame({\n        Size             = UDim2.new(1, 0, 0, 68),\n        BackgroundColor3 = T.panel,\n        ClipsDescendants = true,\n        Parent           = notifHolder,\n    })\n    corner(card, 10)\nstroke(card, T.border, 1.5)\n\n    local bar = newFrame({ Size = UDim2.new(0, 3, 1, 0), BackgroundColor3 = col, Parent = card })\n    corner(bar, 2)\n\n    newLabel({\n        Size       = UDim2.new(1, -22, 0, 18),\n        Position   = UDim2.new(0, 13, 0, 10),\n        Text       = title,\n        TextSize   = 13,\n        Font       = Enum.Font.GothamBold,\n        TextColor3 = T.textPri,\n        Parent     = card,\n    })\n    newLabel({\n        Size        = UDim2.new(1, -22, 0, 28),\n        Position    = UDim2.new(0, 13, 0, 30),\n        Text        = content,\n        TextSize    = 11,\n        TextColor3  = T.textSec,\n        TextWrapped = true,\n        Parent      = card,\n    })\n\n    card.Position = UDim2.new(1, 14, 0, 0)\ntw(card, { Position = UDim2.new(0, 0, 0, 0) }, 0.3, Enum.EasingStyle.Back)\n\n    local prog = newFrame({\n        Size             = UDim2.new(1, 0, 0, 2),\n        Position         = UDim2.new(0, 0, 1, -2),\n        BackgroundColor3 = col,\n        BackgroundTransparency = 0.5,\n        Parent           = card,\n    })\ntw(prog, { Size = UDim2.new(0, 0, 0, 2) }, duration, Enum.EasingStyle.Linear)\n\n    task.delay(duration, function()\n        tw(card, { Position = UDim2.new(1, 14, 0, 0), BackgroundTransparency = 1 }, 0.25)\n        task.wait(0.3)\n        pcall(function() card:Destroy() end)\n    end)\nend\n\n-- ══════════════════════════════════════════════════════\n--  CREATE WINDOW\n-- ══════════════════════════════════════════════════════\n\nfunction ESLib:CreateWindow(config)\n    config = config or {}\n\n    local gui = Instance.new("ScreenGui")\n    gui.Name            = "ESHub"\n    gui.ResetOnSpawn    = false\n    gui.ZIndexBehavior  = Enum.ZIndexBehavior.Sibling\n    gui.IgnoreGuiInset  = true\n    gui.DisplayOrder    = 100\ngui.Parent          = PlayerGui\n\n    local shadow = newFrame({\n        AnchorPoint            = Vector2.new(0.5, 0.5),\n        Position               = UDim2.new(0.5, 3, 0.5, 5),\n        Size                   = UDim2.new(0, WIN_W + 14, 0, WIN_H + 14),\n        BackgroundColor3       = T.black,\n        BackgroundTransparency = 0.5,\n        ZIndex                 = 1,\n        Parent                 = gui,\n    })\n    corner(shadow, 18)\n\n    local win = newFrame({\n        AnchorPoint      = Vector2.new(0.5, 0.5),\n        Position         = UDim2.new(0.5, 0, 0.5, 0),\n        Size             = UDim2.new(0, WIN_W, 0, WIN_H),\n        BackgroundColor3 = T.bg,\n        ClipsDescendants = true,\n        ZIndex           = 2,\n        Parent           = gui,\n    })\n    corner(win, 16)\n\n    local borderOverlay = newFrame({\n        AnchorPoint            = Vector2.new(0.5, 0.5),\n        Position               = UDim2.new(0.5, 0, 0.5, 0),\n        Size                   = UDim2.new(0, WIN_W, 0, WIN_H),\n        BackgroundTransparency = 1,\n        ZIndex                 = 10,\n        Parent                 = gui,\n    })\n    corner(borderOverlay, 16)\nstroke(borderOverlay, T.border, 1.5)\n\n    -- Header\n    local header = newFrame({\n        Size             = UDim2.new(1, 0, 0, HEADER_H),\n        BackgroundColor3 = T.sidebar,\n        ZIndex           = 4,\n        Parent           = win,\n    })\n    newFrame({\n        Size             = UDim2.new(1, 0, 0, 1),\n        Position         = UDim2.new(0, 0, 1, -1),\n        BackgroundColor3 = T.border,\n        ZIndex           = 4,\n        Parent           = header,\n    })\n\n    -- ES Logo badge in header\n    local badge = Instance.new("ImageLabel")\nbadge.Size                   = UDim2.new(0, 32, 0, 32)\nbadge.Position               = UDim2.new(0, 8, 0.5, -16)\nbadge.BackgroundTransparency = 1\nbadge.Image                  = "rbxassetid://138296930859915"\nbadge.ScaleType              = Enum.ScaleType.Fit\nbadge.ZIndex                 = 5\nbadge.Parent                 = header\n\n    newLabel({\n        Size           = UDim2.new(0, 240, 1, 0),\n        Position       = UDim2.new(0, 48, 0, 0),\n        Text           = config.Name or "Extreme Solutions",\n        TextSize       = 14,\n        Font           = Enum.Font.GothamBold,\n        TextColor3     = T.textPri,\n        TextXAlignment = Enum.TextXAlignment.Left,\n        ZIndex         = 5,\n        Parent         = header,\n    })\n\n    newLabel({\n        Size           = UDim2.new(0, 180, 1, 0),\n        Position       = UDim2.new(0.5, -90, 0, 0),\n        Text           = config.Subtitle or "",\n        TextSize       = 11,\n        TextColor3     = T.textDim,\n        TextXAlignment = Enum.TextXAlignment.Center,\n        ZIndex         = 5,\n        Parent         = header,\n    })\n\n    -- Window control buttons\n    local function makeCtrl(offsetX, label, hoverColor)\n        local b = newBtn({\n            Size             = UDim2.new(0, 26, 0, 26),\n            Position         = UDim2.new(1, offsetX, 0.5, -13),\n            BackgroundColor3 = T.card,\n            Text             = label,\n            TextSize         = 12,\n            Font             = Enum.Font.GothamBold,\n            TextColor3       = T.textSec,\n            TextXAlignment   = Enum.TextXAlignment.Center,\n            ZIndex           = 6,\n            Parent           = header,\n        })\n        corner(b, 7)\nstroke(b, T.border, 1)\nb.MouseEnter:Connect(function() tw(b, { BackgroundColor3 = hoverColor, TextColor3 = T.white }, 0.15) end)\nb.MouseLeave:Connect(function() tw(b, { BackgroundColor3 = T.card,     TextColor3 = T.textSec }, 0.15) end)\n        return b\n    end\n\n    local closeBtn = makeCtrl(-36, "X", T.error)\n    local minBtn   = makeCtrl(-68, "-", T.accentDark)\n\n    -- Sidebar\n    local sidebar = newFrame({\n        Size             = UDim2.new(0, SIDEBAR_W, 0, CONTENT_H),\n        Position         = UDim2.new(0, 0, 0, HEADER_H),\n        BackgroundColor3 = T.sidebar,\n        ZIndex           = 3,\n        Parent           = win,\n    })\n    newFrame({\n        Size             = UDim2.new(0, 1, 1, 0),\n        Position         = UDim2.new(1, -1, 0, 0),\n        BackgroundColor3 = T.border,\n        ZIndex           = 3,\n        Parent           = sidebar,\n    })\n\n    local brandStrip = newFrame({\n        Size             = UDim2.new(1, -2, 0, 28),\n        Position         = UDim2.new(0, 0, 1, -28),\n        BackgroundColor3 = T.bg,\n        ZIndex           = 4,\n        Parent           = sidebar,\n    })\n    newLabel({\n        Size           = UDim2.new(1, 0, 1, 0),\n        Text           = "Extreme Solutions",\n        TextSize       = 10,\n        Font           = Enum.Font.GothamBold,\n        TextColor3     = T.accent,\n        TextXAlignment = Enum.TextXAlignment.Center,\n        TextYAlignment = Enum.TextYAlignment.Center,\n        ZIndex         = 5,\n        Parent         = brandStrip,\n    })\n\n    local tabListScroll = scrollFrame(sidebar, 4)\ntabListScroll.Size     = UDim2.new(1, 0, 1, -34)\ntabListScroll.Position = UDim2.new(0, 0, 0, 6)\nlistLayout(tabListScroll, 2)\npad(tabListScroll, 0, 6, 0, 6)\n\n    -- Content area\n    local contentArea = newFrame({\n        Size             = UDim2.new(0, CONTENT_W, 0, CONTENT_H),\n        Position         = UDim2.new(0, SIDEBAR_W, 0, HEADER_H),\n        BackgroundColor3 = T.panel,\n        ZIndex           = 2,\n        Parent           = win,\n    })\n\n    -- Drag\n    do\n        local dragging, dragInput, dragStart, startWin, startShadow\n\n        local function onDragBegan(input)\n            if input.UserInputType == Enum.UserInputType.MouseButton1 then\n                dragging    = true\n                dragStart   = input.Position\n                startWin    = win.Position\n                startShadow = shadow.Position\n                input.Changed:Connect(function()\n                    if input.UserInputState == Enum.UserInputState.End then dragging = false end\n                end)\n            end\n        end\n        local function onDragMoved(input)\n            if input.UserInputType == Enum.UserInputType.MouseMovement then dragInput = input end\n        end\n\n        header.InputBegan:Connect(onDragBegan)\n        sidebar.InputBegan:Connect(onDragBegan)\n        header.InputChanged:Connect(onDragMoved)\n        sidebar.InputChanged:Connect(onDragMoved)\n\n        UIS.InputChanged:Connect(function(input)\n            if input == dragInput and dragging then\n                local d    = input.Position - dragStart\n                local vp   = game:GetService("Workspace").CurrentCamera.ViewportSize\n                local newX = math.clamp(startWin.X.Offset + d.X, WIN_W / 2 - vp.X / 2, vp.X / 2 - WIN_W / 2)\n                local newY = math.clamp(startWin.Y.Offset + d.Y, WIN_H / 2 - vp.Y / 2, vp.Y / 2 - WIN_H / 2)\n                win.Position           = UDim2.new(startWin.X.Scale,    newX,     startWin.Y.Scale,    newY)\n                shadow.Position        = UDim2.new(startShadow.X.Scale, newX + 3, startShadow.Y.Scale, newY + 5)\n                borderOverlay.Position = UDim2.new(startWin.X.Scale,    newX,     startWin.Y.Scale,    newY)\n            end\n        end)\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  MINI BUBBLE  (shown when minimised)\n    --  Shrinks down to ES logo with green glow ring\n    -- ══════════════════════════════════════════════════════\n\n    -- Outer glow ring — slightly larger than the bubble\n    local glowRing = newFrame({\n        AnchorPoint            = Vector2.new(0.5, 0.5),\n        Position               = UDim2.new(1, -60, 1, -60),\n        Size                   = UDim2.new(0, 104, 0, 104),\n        BackgroundColor3       = T.accent,\n        BackgroundTransparency = 0.55,\n        ZIndex                 = 19,\n        Visible                = false,\n        Parent                 = gui,\n    })\n    corner(glowRing, 52)\n\n    -- Main bubble frame\n    local miniBubble = newFrame({\n        AnchorPoint      = Vector2.new(0.5, 0.5),\n        Position         = UDim2.new(1, -60, 1, -60),\n        Size             = UDim2.new(0, 84, 0, 84),\n        BackgroundColor3 = T.bg,\n        ZIndex           = 20,\n        Visible          = false,\n        Parent           = gui,\n    })\n    corner(miniBubble, 42)\n\n    -- Green accent stroke border on bubble\n    local bubbleStroke = Instance.new("UIStroke")\nbubbleStroke.Color           = T.accent\nbubbleStroke.Thickness       = 2.5\nbubbleStroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border\nbubbleStroke.Parent          = miniBubble\n\n    -- ES Logo image inside the bubble\n    local bubbleImg                      = Instance.new("ImageLabel")\nbubbleImg.Size                       = UDim2.new(0, 68, 0, 68)\nbubbleImg.Position                   = UDim2.new(0.5, -34, 0.5, -34)\nbubbleImg.BackgroundTransparency     = 1\nbubbleImg.Image                      = "rbxassetid://138296930859915"\nbubbleImg.ScaleType                  = Enum.ScaleType.Fit\nbubbleImg.ZIndex                     = 21\nbubbleImg.Parent                     = miniBubble\n\n    -- Pulsing glow animation (oscillates between 0.55 and 0.75 for visible glow)\n    local glowTween = TweenService:Create(\n        glowRing,\n        TweenInfo.new(1.2, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true),\n        { BackgroundTransparency = 0.75 }\n    )\nglowTween:Play()\n\n    -- Minimize / Close\n    local minimised = false\n\n    local function restoreWindow()\n        minimised             = false\n        miniBubble.Visible    = false\n        glowRing.Visible      = false\n        win.Visible           = true\n        shadow.Visible        = true\n        borderOverlay.Visible = true\n    end\n\n    local function minimiseWindow()\n        minimised             = true\n        win.Visible           = false\n        shadow.Visible        = false\n        borderOverlay.Visible = false\n        miniBubble.Visible    = true\n        glowRing.Visible      = true\n    end\n\n    minBtn.MouseButton1Click:Connect(function()\n        if minimised then restoreWindow() else minimiseWindow() end\n    end)\n\n    miniBubble.InputBegan:Connect(function(input)\n        if input.UserInputType == Enum.UserInputType.MouseButton1 then\n            restoreWindow()\n        end\n    end)\n\n    closeBtn.MouseButton1Click:Connect(function()\n        gui:Destroy()\n    end)\n\n    -- ══════════════════════════════════════════════════════\n    --  TAB SYSTEM\n    -- ══════════════════════════════════════════════════════\n\n    local tabs    = {}\n    local pages   = {}\n    local current = nil\n\n    local function activateTab(tabObj)\n        for _, t in ipairs(tabs) do\n            local isActive = (t == tabObj)\n            tw(t, {\n                BackgroundColor3 = isActive and T.tabActive or T.sidebar,\n                TextColor3       = isActive and T.accent   or T.textSec,\n            }, 0.15)\n            if t:FindFirstChildOfClass("UIStroke") then\n                t:FindFirstChildOfClass("UIStroke").Color = isActive and T.accentDark or T.border\n            end\n        end\n\n        for tabRef, page in pairs(pages) do\n            page.Visible = (tabRef == tabObj)\n        end\n\n        current = tabObj\n    end\n\n    function ESLib:AddTab(name, icon)\n        local idx = #tabs + 1\n\n        local tabBtn = newBtn({\n            Size             = UDim2.new(1, 0, 0, 32),\n            BackgroundColor3 = T.sidebar,\n            Text             = (icon and icon .. "  " or "") .. name,\n            TextSize         = 12,\n            Font             = Enum.Font.GothamSemibold,\n            TextColor3       = T.textSec,\n            TextXAlignment   = Enum.TextXAlignment.Left,\n            LayoutOrder      = idx,\n            ZIndex           = 5,\n            Parent           = tabListScroll,\n        })\n        corner(tabBtn, 6)\nstroke(tabBtn, T.border, 1)\npad(tabBtn, 0, 0, 0, 10)\n\n        tabBtn.MouseEnter:Connect(function()\n            if tabBtn ~= current then\n                tw(tabBtn, { BackgroundColor3 = T.tabHov }, 0.12)\n            end\n        end)\n        tabBtn.MouseLeave:Connect(function()\n            if tabBtn ~= current then\n                tw(tabBtn, { BackgroundColor3 = T.sidebar }, 0.12)\n            end\n        end)\n\n        local page = scrollFrame(contentArea, 3)\n        page.Size    = UDim2.new(1, 0, 1, 0)\n        page.Visible = false\n        listLayout(page, 6)\npad(page, 10, 10, 10, 10)\n\n        tabs[idx]    = tabBtn\npages[tabBtn] = page\n\n        tabBtn.MouseButton1Click:Connect(function()\n            activateTab(tabBtn)\n        end)\n\n        if idx == 1 then activateTab(tabBtn) end\n\n        return page\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  SECTION\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddSection(parent, title)\n        local sect = newFrame({\n            Size             = UDim2.new(1, 0, 0, 0),\n            BackgroundColor3 = T.card,\n            AutomaticSize    = Enum.AutomaticSize.Y,\n            Parent           = parent,\n        })\n        corner(sect, 8)\nstroke(sect, T.border, 1)\n\n        local header2 = newLabel({\n            Size       = UDim2.new(1, 0, 0, 26),\n            Text       = "  " .. title,\n            TextSize   = 11,\n            Font       = Enum.Font.GothamBold,\n            TextColor3 = T.accent,\n            ZIndex     = 4,\n            Parent     = sect,\n        })\n\n        local body = newFrame({\n            Size             = UDim2.new(1, 0, 0, 0),\n            Position         = UDim2.new(0, 0, 0, 26),\n            BackgroundTransparency = 1,\n            AutomaticSize    = Enum.AutomaticSize.Y,\n            Parent           = sect,\n        })\n        listLayout(body, 4)\npad(body, 4, 8, 8, 8)\n\n        return body\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  TOGGLE\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddToggle(parent, label, default, callback)\n        local state = default or false\n\n        local row = newFrame({\n            Size             = UDim2.new(1, 0, 0, 30),\n            BackgroundColor3 = T.panel,\n            Parent           = parent,\n        })\n        corner(row, 6)\n\n        newLabel({\n            Size     = UDim2.new(1, -52, 1, 0),\n            Position = UDim2.new(0, 10, 0, 0),\n            Text     = label,\n            ZIndex   = 4,\n            Parent   = row,\n        })\n\n        local track = newFrame({\n            Size             = UDim2.new(0, 36, 0, 18),\n            Position         = UDim2.new(1, -46, 0.5, -9),\n            BackgroundColor3 = state and T.toggleOn or T.toggleOff,\n            ZIndex           = 4,\n            Parent           = row,\n        })\n        corner(track, 9)\n\n        local knob = newFrame({\n            Size             = UDim2.new(0, 12, 0, 12),\n            Position         = state and UDim2.new(1, -15, 0.5, -6) or UDim2.new(0, 3, 0.5, -6),\n            BackgroundColor3 = T.white,\n            ZIndex           = 5,\n            Parent           = track,\n        })\n        corner(knob, 6)\n\n        local function setToggle(val)\n            state = val\ntw(track, { BackgroundColor3 = state and T.toggleOn or T.toggleOff }, 0.2)\ntw(knob,  { Position = state and UDim2.new(1, -15, 0.5, -6) or UDim2.new(0, 3, 0.5, -6) }, 0.2)\n            pcall(callback, state)\n        end\n\n        row.InputBegan:Connect(function(inp)\n            if inp.UserInputType == Enum.UserInputType.MouseButton1 then setToggle(not state) end\n        end)\n\n        return { SetValue = setToggle, GetValue = function() return state end }\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  BUTTON\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddButton(parent, label, callback)\n        local b = newBtn({\n            Size             = UDim2.new(1, 0, 0, 30),\n            BackgroundColor3 = T.card,\n            Text             = "  " .. label,\n            TextSize         = 12,\n            Font             = Enum.Font.GothamSemibold,\n            TextColor3       = T.textPri,\n            ZIndex           = 4,\n            Parent           = parent,\n        })\n        corner(b, 6)\nstroke(b, T.border, 1)\n\n        b.MouseEnter:Connect(function() tw(b, { BackgroundColor3 = T.cardHov }, 0.12) end)\nb.MouseLeave:Connect(function() tw(b, { BackgroundColor3 = T.card },    0.12) end)\nb.MouseButton1Click:Connect(function()\n            tw(b, { BackgroundColor3 = T.accentDark }, 0.08)\n            task.wait(0.12)\n            tw(b, { BackgroundColor3 = T.card }, 0.12)\n            pcall(callback)\n        end)\n\n        return b\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  DROPDOWN\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddDropdown(parent, label, options, default, callback)\n        local selected = default or options[1] or ""\n        local open     = false\n\n        local wrap = newFrame({\n            Size          = UDim2.new(1, 0, 0, 30),\n            BackgroundTransparency = 1,\n            AutomaticSize = Enum.AutomaticSize.Y,\n            ZIndex        = 6,\n            Parent        = parent,\n        })\n\n        local header3 = newBtn({\n            Size             = UDim2.new(1, 0, 0, 30),\n            BackgroundColor3 = T.input,\n            Text             = "  " .. label .. ":  " .. selected,\n            TextSize         = 12,\n            Font             = Enum.Font.Gotham,\n            TextColor3       = T.textPri,\n            ZIndex           = 6,\n            Parent           = wrap,\n        })\n        corner(header3, 6)\nstroke(header3, T.border, 1)\n\n        local dropdown = newFrame({\n            Size             = UDim2.new(1, 0, 0, 0),\n            Position         = UDim2.new(0, 0, 0, 32),\n            BackgroundColor3 = T.card,\n            ClipsDescendants = true,\n            ZIndex           = 7,\n            Visible          = false,\n            Parent           = wrap,\n        })\n        corner(dropdown, 6)\nstroke(dropdown, T.accentDark, 1)\n\n        local innerScroll = scrollFrame(dropdown, 8)\n        innerScroll.Size = UDim2.new(1, 0, 1, 0)\n        listLayout(innerScroll, 2)\npad(innerScroll, 4, 4, 4, 4)\n\n        local function closeDropdown()\n            open = false\ntw(dropdown, { Size = UDim2.new(1, 0, 0, 0) }, 0.15)\n            task.wait(0.15)\ndropdown.Visible = false\n        end\n\n        local function addOption(opt)\n            local btn = newBtn({\n                Size             = UDim2.new(1, 0, 0, 26),\n                BackgroundColor3 = T.card,\n                Text             = "  " .. opt,\n                TextSize         = 11,\n                Font             = Enum.Font.Gotham,\n                TextColor3       = opt == selected and T.accent or T.textPri,\n                ZIndex           = 8,\n                Parent           = innerScroll,\n            })\n            corner(btn, 4)\n            btn.MouseEnter:Connect(function() tw(btn, { BackgroundColor3 = T.cardHov }, 0.1) end)\n            btn.MouseLeave:Connect(function() tw(btn, { BackgroundColor3 = T.card    }, 0.1) end)\n            btn.MouseButton1Click:Connect(function()\n                selected = opt\n                header3.Text = "  " .. label .. ":  " .. selected\n                pcall(callback, selected)\n                closeDropdown()\n            end)\n        end\n\n        for _, opt in ipairs(options) do addOption(opt) end\n\n        header3.MouseButton1Click:Connect(function()\n            open = not open\n            if open then\n                dropdown.Visible = true\n                local h = math.min(#options * 30, 150)\n                tw(dropdown, { Size = UDim2.new(1, 0, 0, h) }, 0.15)\n            else\n                closeDropdown()\n            end\n        end)\n\n        return {\n            SetValue   = function(v) selected = v; header3.Text = "  " .. label .. ":  " .. v end,\n            GetValue   = function() return selected end,\n            AddOption  = addOption,\n        }\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  SLIDER\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddSlider(parent, label, min, max, default, callback)\n        local value = math.clamp(default or min, min, max)\n\n        local row = newFrame({\n            Size             = UDim2.new(1, 0, 0, 44),\n            BackgroundColor3 = T.panel,\n            Parent           = parent,\n        })\n        corner(row, 6)\n\n        local lbl = newLabel({\n            Size     = UDim2.new(1, -60, 0, 20),\n            Position = UDim2.new(0, 10, 0, 4),\n            Text     = label,\n            TextSize = 12,\n            ZIndex   = 4,\n            Parent   = row,\n        })\n\n        local valLbl = newLabel({\n            Size           = UDim2.new(0, 50, 0, 20),\n            Position       = UDim2.new(1, -58, 0, 4),\n            Text           = tostring(value),\n            TextSize       = 12,\n            TextColor3     = T.accent,\n            TextXAlignment = Enum.TextXAlignment.Right,\n            ZIndex         = 4,\n            Parent         = row,\n        })\n\n        local track = newFrame({\n            Size             = UDim2.new(1, -20, 0, 6),\n            Position         = UDim2.new(0, 10, 0, 30),\n            BackgroundColor3 = T.toggleOff,\n            ZIndex           = 4,\n            Parent           = row,\n        })\n        corner(track, 3)\n\n        local fill = newFrame({\n            Size             = UDim2.new((value - min) / (max - min), 0, 1, 0),\n            BackgroundColor3 = T.accent,\n            ZIndex           = 5,\n            Parent           = track,\n        })\n        corner(fill, 3)\n\n        local dragging = false\n\n        local function updateSlider(inputX)\n            local rel   = math.clamp((inputX - track.AbsolutePosition.X) / track.AbsoluteSize.X, 0, 1)\n            value       = math.floor(min + rel * (max - min) + 0.5)\n            fill.Size   = UDim2.new(rel, 0, 1, 0)\n            valLbl.Text = tostring(value)\n            pcall(callback, value)\n        end\n\n        track.InputBegan:Connect(function(inp)\n            if inp.UserInputType == Enum.UserInputType.MouseButton1 then\n                dragging = true\n                updateSlider(inp.Position.X)\n            end\n        end)\n\n        UIS.InputEnded:Connect(function(inp)\n            if inp.UserInputType == Enum.UserInputType.MouseButton1 then dragging = false end\n        end)\n\n        UIS.InputChanged:Connect(function(inp)\n            if dragging and inp.UserInputType == Enum.UserInputType.MouseMovement then\n                updateSlider(inp.Position.X)\n            end\n        end)\n\n        return {\n            SetValue = function(v)\n                value = math.clamp(v, min, max)\n                local rel = (value - min) / (max - min)\n                fill.Size   = UDim2.new(rel, 0, 1, 0)\n                valLbl.Text = tostring(value)\n            end,\n            GetValue = function() return value end,\n        }\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  TEXT INPUT\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddTextInput(parent, label, placeholder, callback)\n        local row = newFrame({\n            Size             = UDim2.new(1, 0, 0, 52),\n            BackgroundColor3 = T.panel,\n            Parent           = parent,\n        })\n        corner(row, 6)\n\n        newLabel({\n            Size     = UDim2.new(1, -12, 0, 18),\n            Position = UDim2.new(0, 10, 0, 4),\n            Text     = label,\n            TextSize = 11,\n            ZIndex   = 4,\n            Parent   = row,\n        })\n\n        local box = Instance.new("TextBox")\n        box.Size                   = UDim2.new(1, -20, 0, 22)\n        box.Position               = UDim2.new(0, 10, 0, 24)\n        box.BackgroundColor3       = T.input\n        box.BorderSizePixel        = 0\n        box.Font                   = Enum.Font.Gotham\n        box.TextSize               = 12\n        box.TextColor3             = T.textPri\n        box.PlaceholderText        = placeholder or ""\n        box.PlaceholderColor3      = T.textDim\n        box.Text                   = ""\n        box.ClearTextOnFocus       = false\n        box.ZIndex                 = 4\n        box.Parent                 = row\n        corner(box, 4)\nstroke(box, T.border, 1)\n\n        box.FocusLost:Connect(function(enter)\n            pcall(callback, box.Text, enter)\n        end)\n\n        return box\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  LABEL\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddLabel(parent, text, color)\n        return newLabel({\n            Size       = UDim2.new(1, 0, 0, 22),\n            Text       = "  " .. text,\n            TextSize   = 12,\n            TextColor3 = color or T.textSec,\n            ZIndex     = 4,\n            Parent     = parent,\n        })\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  SEPARATOR\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:AddSeparator(parent)\n        return newFrame({\n            Size             = UDim2.new(1, 0, 0, 1),\n            BackgroundColor3 = T.border,\n            Parent           = parent,\n        })\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  NOTIFY  (expose)\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:Notify(title, content, ntype, duration)\n        notify(title, content, ntype, duration)\n    end\n\n    -- ══════════════════════════════════════════════════════\n    --  CONFIG HELPERS  (expose)\n    -- ══════════════════════════════════════════════════════\n\n    function ESLib:SaveConfig(folder, file, data)  saveConfig(folder, file, data) end\n    function ESLib:LoadConfig(folder, file)        return loadCfg(folder, file)   end\n\n    return ESLib\nend\n\nreturn ESLib